from typing import Callable, Optional, Dict, List, Tuple

class Transition:
    def __init__(self, source: str, event: str, target: str, guard: Optional[Callable] = None):
        self.source = source
        self.event = event
        self.target = target
        self.guard = guard

class StateMachine:
    def __init__(self, initial_state: str):
        self.state = initial_state
        self._transitions: List[Transition] = []
        self._on_enter: Dict[str, List[Callable]] = {}
        self._on_exit: Dict[str, List[Callable]] = {}

    def add_transition(self, source: str, event: str, target: str, guard: Optional[Callable] = None):
        self._transitions.append(Transition(source, event, target, guard))

    def on_enter(self, state: str, action: Callable):
        self._on_enter.setdefault(state, []).append(action)

    def on_exit(self, state: str, action: Callable):
        self._on_exit.setdefault(state, []).append(action)

    def trigger(self, event: str):
        for t in self._transitions:
            if t.source == self.state and t.event == event:
                if t.guard and not t.guard():
                    raise ValueError(f'Guard rejected transition {self.state} -> {t.target}')
                # Exit actions
                for action in self._on_exit.get(self.state, []):
                    action()
                # Transition
                self.state = t.target
                # Enter actions
                for action in self._on_enter.get(self.state, []):
                    action()
                return
        raise ValueError(f'No transition for event "{event}" from state "{self.state}"')
